<?php if($module&&$can('modulos.asignar')):?><section class="card form-card"><h2>Configurar <?= $e($module['nombre']) ?></h2><form method="post" class="form-grid"><input type="hidden" name="_csrf" value="<?= $e($csrfToken) ?>"><input type="hidden" name="id" value="<?= (int)$module['id'] ?>"><div class="read-only-field"><span>Clave</span><strong><?= $e($module['clave']) ?></strong></div><div class="read-only-field"><span>Ruta protegida</span><strong><?= $e($module['ruta']) ?></strong></div><label>Nombre visible<input name="nombre" required maxlength="120" value="<?= $e($module['nombre']) ?>"></label><label>Descripción<input name="descripcion" maxlength="500" value="<?= $e($module['descripcion']) ?>"></label><label>Orden<input type="number" name="orden" min="0" max="65535" required value="<?= (int)$module['orden'] ?>"></label><label>Estado<select name="activo"><option value="1" <?= (int)$module['activo']?'selected':'' ?>>Activo</option><option value="0" <?= !(int)$module['activo']?'selected':'' ?>>Inactivo</option></select></label><label>Visibilidad del menú<select name="visible_menu"><option value="1" <?= (int)$module['visible_menu']?'selected':'' ?>>Visible</option><option value="0" <?= !(int)$module['visible_menu']?'selected':'' ?>>Oculto</option></select></label><fieldset class="check-grid"><legend>Áreas con acceso heredado</legend><?php foreach($areas as$area):?><label><input type="checkbox" name="area_ids[]" value="<?= (int)$area['id'] ?>" <?= in_array((int)$area['id'],$selected,true)?'checked':'' ?>><?= $e($area['nombre']) ?></label><?php endforeach?></fieldset><div class="form-actions"><button class="button button--primary">Guardar configuración</button><a class="button" href="<?= $e(BASE_URL) ?>/index.php?modulo=administracion&amp;seccion=modulos">Cancelar</a></div></form></section><?php endif?></section>
